prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?created ?org ?orgLabel WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org rdfs:label ?orgLabel . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gwName ?gwType ?gwDir ?evDir ?instantiate ?evGwType WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  {
    ?gw a bboExt:ExclusiveGateway .
    ?gw tai:belongsTo ?choreo .
    BIND("ExclusiveGateway" AS ?gwType)
    OPTIONAL { ?gw bbo:name ?gwName . }
    OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
  }
  UNION
  {
    ?gw a bboExt:EventBasedGateway .
    ?gw tai:belongsTo ?choreo .
    BIND("EventBasedGateway" AS ?gwType)
    OPTIONAL { ?gw bbo:name ?gwName . }
    OPTIONAL { ?gw bboExt:gatewayDirection ?evDir . }
    OPTIONAL { ?gw bboExt:instantiate ?instantiate . }
    OPTIONAL { ?gw bboExt:eventGatewayType ?evGwType . }
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mfName ?mfSourceRef ?mfTargetRef ?mfMessageRef WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?mf a bboExt:MessageFlow .
  ?mf tai:belongsTo ?choreo .
  OPTIONAL { ?mf bbo:name ?mfName . }
  OPTIONAL { ?mf bboExt:sourceRef ?mfSourceRef . }
  OPTIONAL { ?mf bboExt:targetRef ?mfTargetRef . }
  OPTIONAL { ?mf bboExt:messageRef ?mfMessageRef . }
}
